/// coeff_token for 8 <= nC: a fixed 6-bit FLC (Table 9-5, column "8 <= nC").
///
/// code = 4 * (TotalCoeff - 1) + TrailingOnes  (for TotalCoeff > 0),
/// length 6. The special "no coefficients" entry (TC=0, T1=0) is `000011`.
#[inline]
fn coeff_token_8(total_coeff: u32, trailing_ones: u32) -> (u32, u32) {
    if total_coeff == 0 {
        return (3, 6); // 000011
    }
    let code = 4 * (total_coeff - 1) + trailing_ones;
    (code, 6)
}

/// coeff_token for nC == -1 (chroma DC, 4:2:0; Table 9-5, column "nC == -1").
/// maxNumCoeff == 4 here.
const COEFF_TOKEN_CHROMA_DC: [[(u32, u32); 5]; 4] = [
    // TrailingOnes == 0
    [
        (1, 2),   // TC=0
        (7, 6),   // TC=1
        (4, 6),   // TC=2
        (3, 6),   // TC=3
        (2, 6),   // TC=4
    ],
    // TrailingOnes == 1
    [
        (0, 0),   // TC=0
        (1, 1),   // TC=1
        (6, 6),   // TC=2
        (3, 7),   // TC=3
        (3, 8),   // TC=4  (per spec)
    ],
    // TrailingOnes == 2
    [
        (0, 0),   // TC=0
        (0, 0),   // TC=1
        (1, 3),   // TC=2
        (2, 7),   // TC=3
        (2, 8),   // TC=4
    ],
    // TrailingOnes == 3
    [
        (0, 0),   // TC=0
        (0, 0),   // TC=1
        (0, 0),   // TC=2
        (5, 6),   // TC=3
        (0, 7),   // TC=4
    ],
];

/// Compute the coeff_token (code, length) for a given (TotalCoeff, TrailingOnes)
/// pair under the nC-selected VLC table.
///
/// `n_c` selects the table:
///   * `n_c >= 8`            -> 6-bit FLC,
///   * `4 <= n_c < 8`        -> Table 9-5 col 3,
///   * `2 <= n_c < 4`        -> Table 9-5 col 2,
///   * `0 <= n_c < 2`        -> Table 9-5 col 1,
///   * `n_c == -1`           -> chroma-DC (4:2:0) table,
///   * `n_c == -2`           -> NOT implemented (4:2:2 chroma DC); falls back to
///                              the `n_c == -1` table as a best-effort.
pub fn coeff_token_bits(total_coeff: u32, trailing_ones: u32, n_c: i32) -> (u32, u32) {
    debug_assert!(trailing_ones <= 3);
    debug_assert!(trailing_ones <= total_coeff);

    if n_c == -1 || n_c == -2 {
        // Chroma DC 4:2:0 (and best-effort for 4:2:2 which is unimplemented).
        return COEFF_TOKEN_CHROMA_DC[trailing_ones as usize][total_coeff as usize];
    }

    if n_c >= 8 {
        return coeff_token_8(total_coeff, trailing_ones);
    }

    let table: &[[(u32, u32); CT_TC]; 4] = if n_c >= 4 {
        &COEFF_TOKEN_2
    } else if n_c >= 2 {
        &COEFF_TOKEN_1
    } else {
        &COEFF_TOKEN_0
    };

    table[trailing_ones as usize][total_coeff as usize]
}

