// residual_block_cavlc
// ─────────────────────────────────────────────────────────────────────────────

/// Write one CAVLC residual block (ITU-T H.264 §9.2 `residual_block_cavlc`).
///
/// `coeffs` are the transform coefficients in **zig-zag scan order** (lowest
/// frequency first). Only the first `max_num_coeff` entries are considered
/// (16 for a luma 4×4 / AC block, 15 for an AC block fed a 16-slot array,
/// 4 for chroma DC). `n_c` selects the coeff_token VLC table (see
/// [`coeff_token_bits`]).
///
/// The remaining entries of `coeffs` beyond `max_num_coeff` are ignored.
pub fn write_residual_4x4(
    bw: &mut BitWriter,
    coeffs: &[i32; 16],
    n_c: i32,
    max_num_coeff: usize,
) {
    let max_n = max_num_coeff.min(16);

    // ── Pass 1: gather non-zero levels from highest frequency downward,
    // and compute TotalCoeff + TrailingOnes.
    // We scan from index (max_n-1) down to 0. The first up-to-3 non-zero
    // coefficients (in this high->low order) that have |level| == 1 are the
    // trailing ones; a non-zero with |level| != 1 terminates the trailing-one
    // run.
    let mut levels: Vec<i32> = Vec::with_capacity(max_n); // high->low order
    let mut positions: Vec<usize> = Vec::with_capacity(max_n); // zig-zag positions, high->low
    for i in (0..max_n).rev() {
        let c = coeffs[i];
        if c != 0 {
            levels.push(c);
            positions.push(i);
        }
    }

    let total_coeff = levels.len() as u32;

    // TrailingOnes: count leading (in high->low order) coefficients with |v|==1,
    // up to 3.
    let mut trailing_ones: u32 = 0;
    for &lv in levels.iter() {
        if lv.abs() == 1 && trailing_ones < 3 {
            trailing_ones += 1;
        } else {
            break;
        }
    }

    // ── coeff_token ──
    let (ct_code, ct_len) = coeff_token_bits(total_coeff, trailing_ones, n_c);
    bw.put_bits(ct_code, ct_len);

    if total_coeff == 0 {
        return; // nothing else coded
    }

    // ── trailing_ones_sign_flag (1 = negative) ──
    for k in 0..trailing_ones as usize {
        let sign = if levels[k] < 0 { 1 } else { 0 };
        bw.put_bit(sign);
    }

    // ── level coding for the remaining (TotalCoeff - TrailingOnes) levels ──
    // suffixLength initialization (§9.2.2.1):
    //   if TotalCoeff > 10 && TrailingOnes < 3 -> suffixLength = 1, else 0.
    let mut suffix_length: u32 = if total_coeff > 10 && trailing_ones < 3 { 1 } else { 0 };

    // For the first non-trailing-one level, when TrailingOnes < 3 the encoder
    // subtracts the bias of the implied sign of the smallest representable level
    // (the level_prefix == 14 / suffixLength==0 special and the +/-1 reservation).
    let mut first_non_t1 = true;

    for k in trailing_ones as usize..total_coeff as usize {
        let level = levels[k];

        // Map signed level to a non-negative levelCode (§9.2.2.1).
        // levelCode = 2*|level| - 2 if level > 0, else 2*|level| - 1.
        let mut level_code: i32 = if level > 0 {
            2 * level - 2
        } else {
            -2 * level - 1
        };

        // For the first non-trailing-one coefficient, if there were fewer than 3
        // trailing ones, subtract 2 (the ±1 magnitudes are reserved for T1s).
        if first_non_t1 && trailing_ones < 3 {
            level_code -= 2;
        }
        first_non_t1 = false;

        let level_code = level_code as u32;

        // Split levelCode into level_prefix and level_suffix per suffixLength.
        let (level_prefix, level_suffix, suffix_bits) =
            split_level_code(level_code, suffix_length);

        // Write level_prefix as unary: `level_prefix` zeros then a `1`.
        for _ in 0..level_prefix {
            bw.put_bit(0);
        }
        bw.put_bit(1);

        // Write level_suffix with `suffix_bits` bits.
        if suffix_bits > 0 {
            bw.put_bits(level_suffix, suffix_bits);
        }

        // Adaptive update of suffixLength (§9.2.2.1).
        if suffix_length == 0 {
            suffix_length = 1;
        }
        // threshold = 3 << (suffixLength - 1)
        let threshold = 3u32 << (suffix_length - 1);
        if level.unsigned_abs() > threshold && suffix_length < 6 {
            suffix_length += 1;
        }
    }

    // ── total_zeros ──
    // total_zeros = sum of zeros located before the last non-zero coefficient,
    // in the zig-zag scan. positions[] are high->low; the lowest position is
    // positions.last() (the first non-zero in scan order is the highest index).
    // total_zeros = (highest non-zero zig-zag index) + 1 - TotalCoeff.
    let highest_pos = positions[0]; // highest zig-zag index that is non-zero
    let total_zeros = (highest_pos as u32 + 1) - total_coeff;

    if total_coeff < max_n as u32 {
        write_total_zeros(bw, total_coeff, total_zeros, max_num_coeff);
    }

    // ── run_before ──
    // Walk the non-zero coefficients from highest frequency to lowest. For each
    // (except the last, lowest-frequency one) write run_before given zerosLeft.
    // run_before[i] = number of zeros immediately preceding coefficient i in
    // the high->low scan (i.e. between this coeff and the next lower-index one).
    let mut zeros_left = total_zeros;
    // positions are high->low: positions[0] highest, positions[last] lowest.
    for i in 0..(total_coeff as usize) {
        if zeros_left == 0 {
            break;
        }
        // For the last coefficient (lowest frequency, positions[last]),
        // run_before is not coded — its run is implied by remaining zerosLeft.
        if i == (total_coeff as usize - 1) {
            break;
        }
        let cur = positions[i];
        let next = positions[i + 1];
        // zeros strictly between next (lower index) and cur (higher index).
        let run_before = (cur - next - 1) as u32;
        write_run_before(bw, run_before, zeros_left);
        zeros_left -= run_before;
    }
}

/// Split a non-negative levelCode into (level_prefix, level_suffix, suffix_bits)
/// per ITU-T H.264 §9.2.2.1. This is the exact inverse of the decoder's
/// reconstruction, including the full `level_prefix >= 16` escape ladder (the
/// suffix GROWS as `level_prefix - 3`, not a fixed 12 bits — required for the
/// large levels produced at low QP). Implemented as the standard search over
/// candidate prefixes, matching conformant encoders bit-for-bit.
fn split_level_code(level_code: u32, suffix_length: u32) -> (u32, u32, u32) {
    let level_code = level_code as i64;
    let mut level_prefix: u32 = 0;
    loop {
        // levelSuffixSize for this candidate prefix (decoder rule).
        let suffix_bits: u32 = if level_prefix == 14 && suffix_length == 0 {
            4
        } else if level_prefix >= 15 {
            level_prefix - 3
        } else {
            suffix_length
        };

        // Reconstruct the levelCode the DECODER would compute for
        // (level_prefix, level_suffix == 0) — i.e. the base of this prefix's range.
        // decoder: levelCode = min(15,prefix) << suffixLength
        //          + (prefix>=16 ? (1<<(prefix-3)) - 4096 : 0)
        //          + (prefix>=15 && suffixLength==0 ? 15 : 0)
        let mut base: i64 = (level_prefix.min(15) as i64) << suffix_length;
        if level_prefix >= 16 {
            base += (1i64 << (level_prefix - 3)) - 4096;
        }
        if level_prefix >= 15 && suffix_length == 0 {
            base += 15;
        }

        let level_max: i64 = base + ((1i64 << suffix_bits) - 1);
        if level_code <= level_max && level_code >= base {
            let level_suffix = (level_code - base) as u32;
            return (level_prefix, level_suffix, suffix_bits);
        }
        level_prefix += 1;
        // Safety: prefixes never exceed a small bound for 8-bit residuals.
        debug_assert!(level_prefix < 64, "level_prefix overflow for levelCode {}", level_code);
    }
}

/// Write the total_zeros VLC. `total_coeff` selects the row; `total_zeros` the
/// column. Picks the 4×4 (maxNumCoeff up to 16) or chroma-DC (maxNumCoeff == 4)
/// table by `max_num_coeff`.
fn write_total_zeros(bw: &mut BitWriter, total_coeff: u32, total_zeros: u32, max_num_coeff: usize) {
    if max_num_coeff <= 4 {
        // chroma DC 2×2
        let (code, len) = TOTAL_ZEROS_CHROMA_DC[(total_coeff - 1) as usize][total_zeros as usize];
        debug_assert!(len > 0, "invalid chroma-DC total_zeros slot");
        bw.put_bits(code, len);
    } else {
        let (code, len) = TOTAL_ZEROS_4X4[(total_coeff - 1) as usize][total_zeros as usize];
        debug_assert!(len > 0, "invalid total_zeros slot tc={} tz={}", total_coeff, total_zeros);
        bw.put_bits(code, len);
    }
}

/// Write a single run_before VLC for the given `zeros_left`.
fn write_run_before(bw: &mut BitWriter, run_before: u32, zeros_left: u32) {
    let idx = (zeros_left.min(7) - 1) as usize;
    let (code, len) = RUN_BEFORE[idx][run_before as usize];
    debug_assert!(len > 0, "invalid run_before slot zl={} rb={}", zeros_left, run_before);
    bw.put_bits(code, len);
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Capture exactly the bits written by `f` (via the bit-string mirror) into
    /// a '0'/'1' string. BitWriter has no partial-bit read-back, so tests assert
    /// against this MSB-first mirror which shares BitWriter's bit semantics.
    fn capture(f: impl FnOnce(&mut CaptureWriter)) -> String {
        let mut cw = CaptureWriter { bits: String::new() };
        f(&mut cw);
        cw.bits
    }

    /// Minimal bit sink mirroring BitWriter's MSB-first semantics so tests can
    /// assert exact bit strings without needing read-back from BitWriter.
    struct CaptureWriter {
        bits: String,
    }
    impl CaptureWriter {
        fn put_bit(&mut self, b: u32) {
            self.bits.push(if b & 1 == 1 { '1' } else { '0' });
        }
        fn put_bits(&mut self, val: u32, n: u32) {
            let mut i = n;
            while i > 0 {
                i -= 1;
                self.put_bit((val >> i) & 1);
            }
        }
    }

    fn coeff_token_str(tc: u32, t1: u32, n_c: i32) -> String {
        let (code, len) = coeff_token_bits(tc, t1, n_c);
        capture(|w| w.put_bits(code, len))
    }

    #[test]
    fn coeff_token_known_low_range() {
        // 0 <= nC < 2 examples (Table 9-5):
        // TotalCoeff=0, T1=0 -> '1'
        assert_eq!(coeff_token_str(0, 0, 0), "1");
        // TotalCoeff=1, T1=1 -> '01'
        assert_eq!(coeff_token_str(1, 1, 0), "01");
        // TotalCoeff=2, T1=2 -> '001' (Table 9-5 col 0<=nC<2; the prior '011'
        // value was a transcription error — '011' collides with the '01' prefix
        // of coeff_token(1,1), which is impossible for a prefix-free VLC).
        assert_eq!(coeff_token_str(2, 2, 0), "001");
        // TotalCoeff=3, T1=3 -> '00011'
        assert_eq!(coeff_token_str(3, 3, 0), "00011");
    }

    #[test]
    fn coeff_token_8plus_is_flc() {
        // nC >= 8: 6-bit FLC. (0,0) -> 000011.
        assert_eq!(coeff_token_str(0, 0, 8), "000011");
        // TC=1, T1=0 -> code = 4*0 + 0 = 0 -> 000000
        assert_eq!(coeff_token_str(1, 0, 8), "000000");
        // TC=1, T1=1 -> code = 1 -> 000001
        assert_eq!(coeff_token_str(1, 1, 8), "000001");
        // TC=2, T1=2 -> code = 4*1 + 2 = 6 -> 000110
        assert_eq!(coeff_token_str(2, 2, 8), "000110");
    }

    #[test]
    fn coeff_token_chroma_dc() {
        // nC == -1 (chroma DC). (0,0) -> '01' (Table 9-5 col nC==-1).
        assert_eq!(coeff_token_str(0, 0, -1), "01");
        // (1,1) -> '1'
        assert_eq!(coeff_token_str(1, 1, -1), "1");
        // (2,2) -> '001'
        assert_eq!(coeff_token_str(2, 2, -1), "001");
    }

    #[test]
    fn total_zeros_lengths() {
        // total_zeros table sanity: a few known entries from Table 9-7.
        // TotalCoeff=1, total_zeros=0 -> code 1, len 1.
        assert_eq!(TOTAL_ZEROS_4X4[0][0], (1, 1));
        // TotalCoeff=1, total_zeros=1 -> code 3, len 3 ('011').
        assert_eq!(TOTAL_ZEROS_4X4[0][1], (3, 3));
        // TotalCoeff=3, total_zeros=0 -> (5,4).
        assert_eq!(TOTAL_ZEROS_4X4[2][0], (5, 4));
        // TotalCoeff=15, total_zeros=0 -> (0,1); =1 -> (1,1).
        assert_eq!(TOTAL_ZEROS_4X4[14][0], (0, 1));
        assert_eq!(TOTAL_ZEROS_4X4[14][1], (1, 1));
    }

    #[test]
    fn run_before_lengths() {
        // zerosLeft==1: run_before 0 -> '1', 1 -> '0'.
        assert_eq!(RUN_BEFORE[0][0], (1, 1));
        assert_eq!(RUN_BEFORE[0][1], (0, 1));
        // zerosLeft==3: run_before 0 -> '11', etc.
        assert_eq!(RUN_BEFORE[2][0], (3, 2));
        // zerosLeft>=7: run_before 0 -> '111', run_before 6 -> '001', run_before 7 -> 4 bits.
        assert_eq!(RUN_BEFORE[6][0], (7, 3));
        assert_eq!(RUN_BEFORE[6][6], (1, 3));
        assert_eq!(RUN_BEFORE[6][7], (1, 4));
    }

    /// Capture-equivalent of write_residual_4x4 so tests can read exact bits.
    /// Mirrors the real function but routes through CaptureWriter.
    fn residual_str(coeffs: &[i32; 16], n_c: i32, max_num_coeff: usize) -> String {
        // Use the real BitWriter, then count bits by also building via capture.
        // We re-run the same logic on a CaptureWriter by adapting: simplest is to
        // expose the bit string by writing into a real BitWriter and decoding the
        // produced bytes up to the known bit length. But we don't track bit length.
        // Instead, compute it through a tiny shim that re-runs the algorithm.
        capture(|w| write_residual_capture(w, coeffs, n_c, max_num_coeff))
    }

    // A capture-mirror of write_residual_4x4 for exact-bit tests.
    fn write_residual_capture(
        bw: &mut CaptureWriter,
        coeffs: &[i32; 16],
        n_c: i32,
        max_num_coeff: usize,
    ) {
        let max_n = max_num_coeff.min(16);
        let mut levels: Vec<i32> = Vec::new();
        let mut positions: Vec<usize> = Vec::new();
        for i in (0..max_n).rev() {
            if coeffs[i] != 0 {
                levels.push(coeffs[i]);
                positions.push(i);
            }
        }
        let total_coeff = levels.len() as u32;
        let mut trailing_ones = 0u32;
        for &lv in levels.iter() {
            if lv.abs() == 1 && trailing_ones < 3 {
                trailing_ones += 1;
            } else {
                break;
            }
        }
        let (ct_code, ct_len) = coeff_token_bits(total_coeff, trailing_ones, n_c);
        bw.put_bits(ct_code, ct_len);
        if total_coeff == 0 {
            return;
        }
        for k in 0..trailing_ones as usize {
            bw.put_bit(if levels[k] < 0 { 1 } else { 0 });
        }
        let mut suffix_length = if total_coeff > 10 && trailing_ones < 3 { 1 } else { 0 };
        let mut first_non_t1 = true;
        for k in trailing_ones as usize..total_coeff as usize {
            let level = levels[k];
            let mut level_code: i32 = if level > 0 { 2 * level - 2 } else { -2 * level - 1 };
            if first_non_t1 && trailing_ones < 3 {
                level_code -= 2;
            }
            first_non_t1 = false;
            let (lp, ls, sb) = split_level_code(level_code as u32, suffix_length);
            for _ in 0..lp {
                bw.put_bit(0);
            }
            bw.put_bit(1);
            if sb > 0 {
                bw.put_bits(ls, sb);
            }
            if suffix_length == 0 {
                suffix_length = 1;
            }
            let threshold = 3u32 << (suffix_length - 1);
            if level.unsigned_abs() > threshold && suffix_length < 6 {
                suffix_length += 1;
            }
        }
        let highest_pos = positions[0];
        let total_zeros = (highest_pos as u32 + 1) - total_coeff;
        if total_coeff < max_n as u32 {
            let (code, len) = if max_num_coeff <= 4 {
                TOTAL_ZEROS_CHROMA_DC[(total_coeff - 1) as usize][total_zeros as usize]
            } else {
                TOTAL_ZEROS_4X4[(total_coeff - 1) as usize][total_zeros as usize]
            };
            bw.put_bits(code, len);
        }
        let mut zeros_left = total_zeros;
        for i in 0..(total_coeff as usize) {
            if zeros_left == 0 || i == total_coeff as usize - 1 {
                break;
            }
            let run_before = (positions[i] - positions[i + 1] - 1) as u32;
            let idx = (zeros_left.min(7) - 1) as usize;
            let (code, len) = RUN_BEFORE[idx][run_before as usize];
            bw.put_bits(code, len);
            zeros_left -= run_before;
        }
    }

    #[test]
    fn all_zero_block_writes_only_coeff_token() {
        let coeffs = [0i32; 16];
        // For 0 <= nC < 2, coeff_token(0,0) is '1'.
        let s = residual_str(&coeffs, 0, 16);
        assert_eq!(s, "1", "all-zero block must emit only coeff_token(0,0)");
    }

    #[test]
    fn small_known_block_shape() {
        // zig-zag coeffs: [3, 1, -1, 0, ...]. Scanning high->low:
        // positions with nonzero: index 2 (=-1), index 1 (=1), index 0 (=3).
        // levels high->low = [-1, 1, 3]. TotalCoeff = 3.
        // TrailingOnes: first |.|==1 -> -1 (T1=1), next 1 (T1=2), next 3 stops. T1=2.
        let mut coeffs = [0i32; 16];
        coeffs[0] = 3;
        coeffs[1] = 1;
        coeffs[2] = -1;

        // Verify the derived TotalCoeff / TrailingOnes via direct recompute.
        let max_n = 16;
        let mut levels = Vec::new();
        for i in (0..max_n).rev() {
            if coeffs[i] != 0 {
                levels.push(coeffs[i]);
            }
        }
        assert_eq!(levels, vec![-1, 1, 3]);
        let total_coeff = levels.len() as u32;
        let mut t1 = 0u32;
        for &lv in &levels {
            if lv.abs() == 1 && t1 < 3 {
                t1 += 1;
            } else {
                break;
            }
        }
        assert_eq!(total_coeff, 3);
        assert_eq!(t1, 2);

        let s = residual_str(&coeffs, 0, 16);
        assert!(!s.is_empty());

        // Bit-exact reconstruction of the expected stream for 0<=nC<2:
        //  coeff_token(TC=3,T1=2) = (5,7) -> '0000101'
        //  trailing_ones_sign: levels[0]=-1 -> '1', levels[1]=1 -> '0'
        //  one remaining level: levels[2]=3 (>0) -> levelCode=2*3-2=4; first
        //    non-T1 with T1<3 -> levelCode-=2 -> 2. suffixLength starts 0.
        //    split(2,0): prefix=2,no suffix -> '001'
        //  total_zeros: highest nonzero zig-zag index = 2, TC=3 -> total_zeros=0.
        //    TC=3,tz=0 -> (5,4) -> '0101'
        //  run_before: zeros_left=0 -> none coded.
        let expected = {
            let ct = capture(|w| w.put_bits(5, 7)); // 0000101
            let signs = "10".to_string();
            let level = capture(|w| {
                // prefix=2 -> '00', then '1'
                w.put_bit(0);
                w.put_bit(0);
                w.put_bit(1);
            });
            let tz = capture(|w| w.put_bits(5, 4)); // 0101
            format!("{}{}{}{}", ct, signs, level, tz)
        };
        assert_eq!(s, expected, "small block bitstream mismatch");
    }

    #[test]
    fn block_with_zeros_and_runs() {
        // A block exercising total_zeros + run_before.
        // zig-zag: index0=2, index1=0, index2=1, index3=0, index4=-1, rest 0.
        // nonzero scan high->low: idx4=-1, idx2=1, idx0=2.
        // levels = [-1, 1, 2]; TC=3; T1: -1(1),1(2),2 stops -> T1=2.
        // highest nonzero index=4 -> total_zeros = 5 - 3 = 2.
        // runs: between idx4 and idx2 -> 4-2-1 = 1 zero; between idx2 and idx0 -> 1 zero.
        let mut coeffs = [0i32; 16];
        coeffs[0] = 2;
        coeffs[2] = 1;
        coeffs[4] = -1;
        let s = residual_str(&coeffs, 0, 16);
        assert!(!s.is_empty());

        // Sanity: plausible length. coeff_token(3,2)@nC0 = 7 bits, 2 sign bits,
        // one level (~3-5 bits), total_zeros (TC=3,tz=2 -> (6,3)=3 bits),
        // run_before for first coeff (zerosLeft=2, run=1 -> (1,2)=2 bits).
        // Should be > 12 bits and < 40.
        assert!(s.len() > 12 && s.len() < 40, "implausible length {}", s.len());
    }

    #[test]
    fn high_total_coeff_suffix_init() {
        // 12 nonzero coeffs, only 2 trailing ones -> suffixLength inits to 1.
        // Build a dense block.
        let mut coeffs = [0i32; 16];
        for i in 0..12 {
            coeffs[i] = if i < 2 { (i as i32) + 2 } else { 1 };
        }
        // Make the two highest-frequency (scan-first) coeffs ±1 so T1=2.
        // coeffs index 10,11 are the highest among the 12 set; set them to 1.
        coeffs[11] = 1;
        coeffs[10] = 1;
        coeffs[0] = 5;
        coeffs[1] = 4;
        let s = residual_str(&coeffs, 0, 16);
        assert!(!s.is_empty());
        // TotalCoeff should be 12.
        let nz = coeffs.iter().filter(|&&c| c != 0).count();
        assert_eq!(nz, 12);
    }
}
